            .as_ref()
            .and_then(|sel| element.select(sel).next())
            .map(|el| el.text().collect::<String>().trim().to_string())
            .unwrap_or_default();

        let url = title_selector
            .as_ref()
            .and_then(|sel| element.select(sel).next())
            .and_then(|el| el.value().attr("href"))
            .unwrap_or("")
            .to_string();

        let snippet = snippet_selector
            .as_ref()
            .and_then(|sel| element.select(sel).next())
            .map(|el| el.text().collect::<String>().trim().to_string())
            .unwrap_or_default();

        if !title.is_empty() || !snippet.is_empty() {
